import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { createProject } from "../../api/api";
import { T, fonts, PageHeader, PrimaryBtn, Input, Textarea, SVGIcon, Card } from "./designSystem";

const CATS = [
  { value:"web-development",     label:"🌐 Web Development" },
  { value:"mobile-development",  label:"📱 Mobile Development" },
  { value:"ui-ux-design",        label:"🎨 UI/UX Design" },
  { value:"graphic-design",      label:"✏️ Graphic Design" },
  { value:"backend-development", label:"⚙️ Backend Development" },
  { value:"data-science",        label:"📊 Data Science & ML" },
  { value:"devops",              label:"🚀 DevOps & Cloud" },
  { value:"content-writing",     label:"📝 Content Writing" },
  { value:"digital-marketing",   label:"📣 Digital Marketing" },
  { value:"video-editing",       label:"🎬 Video Editing" },
  { value:"seo",                 label:"🔍 SEO" },
  { value:"cybersecurity",       label:"🔒 Cybersecurity" },
  { value:"other",               label:"💼 Other" },
];

const SelectInput = ({ label, required, value, onChange, children }) => (
  <div>
    <label style={{ display:"block", fontSize:12, fontWeight:600, color:T.text, marginBottom:7 }}>
      {label}{required && <span style={{ color:T.danger }}> *</span>}
    </label>
    <select value={value} onChange={onChange} style={{
      width:"100%", padding:"11px 14px", borderRadius:10, border:`1.5px solid ${T.border}`,
      fontSize:13, color: value ? T.text : T.muted, background:"#FAFAFA",
      outline:"none", fontFamily:"'DM Sans',sans-serif", boxSizing:"border-box", cursor:"pointer",
    }}
      onFocus={e=>e.target.style.border=`1.5px solid ${T.accent}`}
      onBlur={e=>e.target.style.border=`1.5px solid ${T.border}`}>
      {children}
    </select>
  </div>
);

const PostProject = () => {
  const navigate = useNavigate();
  const [form, setForm] = useState({ title:"", description:"", budget:"", category:"", skills:"", deadline:"" });
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState("");
  const [success, setSuccess] = useState("");

  const set = k => e => setForm(f => ({ ...f, [k]: e.target.value }));

  const handleSubmit = async e => {
    e.preventDefault();
    if (!form.title || !form.description || !form.budget || !form.category) {
      setError("Title, Category, Description and Budget are required."); return;
    }
    setLoading(true); setError(""); setSuccess("");
    try {
      await createProject({ ...form, budget: Number(form.budget) });
      setSuccess("Project posted successfully! Redirecting...");
      setTimeout(() => navigate("/client/my-projects"), 1400);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to post project.");
    }
    setLoading(false);
  };

  return (
    <div style={{ minHeight:"100vh", background:T.pageBg, fontFamily:"'DM Sans',sans-serif" }}>
      <link href={fonts} rel="stylesheet"/>
      <div style={{ maxWidth:740, margin:"0 auto", padding:"36px 28px" }}>

        <PageHeader
          eyebrow="New Opportunity"
          title="Post a New Project"
          subtitle="Fill in the details to find the perfect freelancer."
        />

        <Card>
          <div style={{ padding:"32px 36px" }}>

            {error && (
              <div style={{ background:"#FEF2F2", border:"1px solid #FECACA", borderRadius:10,
                padding:"11px 15px", marginBottom:22, color:T.danger, fontSize:13,
                display:"flex", alignItems:"center", gap:8 }}>
                <SVGIcon d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" color={T.danger} size={15}/>
                {error}
              </div>
            )}
            {success && (
              <div style={{ background:"#D1FAE5", border:"1px solid #6EE7B7", borderRadius:10,
                padding:"11px 15px", marginBottom:22, color:T.success, fontSize:13,
                display:"flex", alignItems:"center", gap:8 }}>
                ✅ {success}
              </div>
            )}

            <form onSubmit={handleSubmit}>
              <div style={{ display:"flex", flexDirection:"column", gap:20 }}>

                <Input label="Project Title" required
                  placeholder="e.g. Build a React E-commerce Website"
                  value={form.title} onChange={set("title")}/>

                <SelectInput label="Category" required value={form.category} onChange={set("category")}>
                  <option value="">-- Select a Category --</option>
                  {CATS.map(c => <option key={c.value} value={c.value}>{c.label}</option>)}
                </SelectInput>

                <Textarea label="Description" required rows={4}
                  placeholder="Describe what you need in detail — requirements, goals, deliverables..."
                  value={form.description} onChange={set("description")}/>

                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:16 }}>
                  <div>
                    <label style={{ display:"block", fontSize:12, fontWeight:600, color:T.text, marginBottom:7 }}>
                      Budget (₹) <span style={{ color:T.danger }}>*</span>
                    </label>
                    <div style={{ position:"relative" }}>
                      <span style={{ position:"absolute", left:13, top:"50%", transform:"translateY(-50%)",
                        color:T.muted, fontWeight:600, fontSize:13 }}>₹</span>
                      <input type="number" placeholder="5000" value={form.budget} onChange={set("budget")}
                        style={{ width:"100%", padding:"11px 14px 11px 26px", borderRadius:10,
                          border:`1.5px solid ${T.border}`, fontSize:13, color:T.text, background:"#FAFAFA",
                          outline:"none", fontFamily:"'DM Sans',sans-serif", boxSizing:"border-box" }}
                        onFocus={e=>e.target.style.border=`1.5px solid ${T.accent}`}
                        onBlur={e=>e.target.style.border=`1.5px solid ${T.border}`}/>
                    </div>
                  </div>
                  <Input label="Deadline" type="date" value={form.deadline} onChange={set("deadline")}/>
                </div>

                <div>
                  <Input label="Required Skills"
                    placeholder="e.g. React, Node.js, MongoDB"
                    value={form.skills} onChange={set("skills")}/>
                  <p style={{ fontSize:11, color:T.muted, marginTop:5 }}>Separate with commas</p>
                </div>

                <div style={{ display:"flex", gap:12, paddingTop:8 }}>
                  <button type="button" onClick={() => navigate("/client/my-projects")} style={{
                    flex:1, padding:"12px", borderRadius:11, border:`1.5px solid ${T.border}`,
                    background:"#fff", color:T.muted, fontSize:13, fontWeight:600, cursor:"pointer",
                    fontFamily:"'DM Sans',sans-serif" }}>
                    Cancel
                  </button>
                  <PrimaryBtn disabled={loading}>
                    <SVGIcon d="M13 10V3L4 14h7v7l9-11h-7z" color="#fff" size={14} stroke={2}/>
                    {loading ? "Posting..." : "Post Project"}
                  </PrimaryBtn>
                </div>
              </div>
            </form>
          </div>
        </Card>
      </div>
    </div>
  );
};
export default PostProject;
